1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with 0 neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1], [2, 1], [0, 2], [1, 2], [2, 2]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
22	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(result).toContainEqual([1, 1]);
25	  });
26	  it("should transform a vertical 3-cell blinker into a horizontal 3-cell blinker", () => {
27	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
28	    const sortFn = (a: number[], b: number[]) => a[0] - b[0] || a[1] - b[1];
29	    expect([...result].sort(sortFn)).toEqual([[-1, 1], [0, 1], [1, 1]].sort(sortFn));
30	  });
31	  it.todo("should leave a 2x2 block unchanged (still life)");
32	  it.todo("should support negative coordinates");
33	});
