1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const parseKey = (key: string): Cell => {
12	  const [x, y] = key.split(",");
13	  return [Number(x), Number(y)];
14	};
15	
16	const survivesOrIsBorn = (isAlive: boolean, neighborCount: number): boolean =>
17	  neighborCount === 3 || (isAlive && neighborCount === 2);
18	
19	export function nextGeneration(cells: Cell[]): Cell[] {
20	  const liveSet = new Set(cells.map(keyOf));
21	  const neighborCounts = new Map<string, number>();
22	
23	  for (const [x, y] of cells) {
24	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
25	      const key = keyOf([x + dx, y + dy]);
26	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
27	    }
28	  }
29	
30	  const result: Cell[] = [];
31	  for (const [key, count] of neighborCounts) {
32	    if (survivesOrIsBorn(liveSet.has(key), count)) {
33	      result.push(parseKey(key));
34	    }
35	  }
36	
37	  return result;
38	}
