it("should leave a 2x2 block unchanged (still life)", () => {
  const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
  const sortFn = (a: number[], b: number[]) => a[0] - b[0] || a[1] - b[1];
  expect([...result].sort(sortFn)).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]].sort(sortFn));
});
